/**
 * Soft spring force toward an anchor (galaxy home) position.
 * @returns {{ fx: number, fy: number }}
 */
export function computeAnchorForce(bodyPos, anchorPos, springK) {
    const dx = anchorPos.x - bodyPos.x;
    const dy = anchorPos.y - bodyPos.y;
    return {
        fx: dx * springK,
        fy: dy * springK,
    };
}

/**
 * Cross-galaxy attraction: pulls a star toward galaxies it has semantic affinity with.
 * @param {{ x: number, y: number }} bodyPos
 * @param {string} postId
 * @param {Map} starPullMap - from buildSemanticMaps
 * @param {Map} galaxyPositions - userId → {x,y}
 * @param {number} pullK
 * @returns {{ fx: number, fy: number }}
 */
export function computeSemanticPullForce(bodyPos, postId, starPullMap, galaxyPositions, pullK) {
