  1→import { useState, useEffect, useRef, useCallback, useMemo } from 'react';
  2→import {
  3→    createStarEngine,
  4→    createStarBody,
  5→    createConstellationConstraint,
  6→    getStarMass,
  7→    getGalaxyMass,
  8→    computeOrbitalVelocity,
  9→    PHYSICS_CONFIG,
 10→    Engine,
 11→    Body,
 12→    World,
 13→    Constraint,
 14→} from '../physics/matterEngine';
 15→import { buildSemanticMaps } from '../physics/semanticForces';
 16→import { buildQuadTree, computeBarnesHutForces } from '../physics/barnesHut';
 17→import { screenToWorld } from '../utils/coordConversion';
 18→import { userHomeCoords, getStarRadius } from '../utils/starUtils';
 19→
 20→/**
 21→ * useStarPhysics — owns the Matter.js engine for star-level physics.
 22→ *
 23→ * Stars get real velocity, collision, air friction, semantic gravity,
 24→ * constellation constraints, and interactive drag-and-throw.
 25→ */
 26→export default function useStarPhysics({
 27→    posts,
 28→    activePostIds,
 29→    galaxyPositions,
 30→    starPulls,
 31→    similarPairs,
 32→    starPullOffsets,
 33→    isGalaxySettled,
 34→    camera,
 35→    zoom,
 36→    stageSize,
 37→    isStarDragging,
 38→    enabled = true,
 39→}) {
 40→    const [starBodyPositions, setStarBodyPositions] = useState(() => new Map());
 41→
 42→    // Refs for the physics engine — not in React state
 43→    const engineRef = useRef(null);
 44→    const bodiesRef = useRef(new Map());          // postId → Matter.Body
 45→    const anchorsRef = useRef(new Map());          // postId → {x, y} anchor target
 46→    const constraintsRef = useRef(new Map());      // "postA|postB" → Matter.Constraint
 47→    const staticTimesRef = useRef(new Map());      // postId → timestamp when set to static
 48→    const rafRef = useRef(null);
 49→    const frameCountRef = useRef(0);
 50→    const lastCleanupRef = useRef(Date.now());
 51→
 52→    // Drag state
 53→    const dragBodyRef = useRef(null);
 54→    const dragConstraintRef = useRef(null);
 55→    const dragPointRef = useRef(null);             // {x,y} fixed world point
 56→
 57→    // Keep latest values in refs for the RAF loop (avoids stale closures)
 58→    const galaxyPositionsRef = useRef(galaxyPositions);
 59→    const semanticMapsRef = useRef({ starPullMap: new Map(), pairMap: new Map() });
 60→    const cameraRef = useRef(camera);
 61→    const zoomRef = useRef(zoom);
 62→    const stageSizeRef = useRef(stageSize);
 63→    const postsMapRef = useRef(new Map());
 64→
 65→    // Sync refs
 66→    galaxyPositionsRef.current = galaxyPositions;
 67→    cameraRef.current = camera;
 68→    zoomRef.current = zoom;
 69→    stageSizeRef.current = stageSize;
 70→
 71→    // Build a postId → post lookup
 72→    useEffect(() => {
 73→        const map = new Map();
 74→        if (Array.isArray(posts)) {
 75→            for (const p of posts) {
 76→                if (p?.id) map.set(p.id, p);
 77→            }
 78→        }
 79→        postsMapRef.current = map;
 80→    }, [posts]);
 81→
 82→    // Pre-process semantic data into O(1) maps
 83→    useEffect(() => {
 84→        semanticMapsRef.current = buildSemanticMaps(starPulls, similarPairs);
 85→    }, [starPulls, similarPairs]);
 86→
 87→    // ── Create engine on mount ────────────────────────────────────────
 88→    useEffect(() => {
 89→        if (!enabled) return;
 90→
 91→        engineRef.current = createStarEngine();
 92→
 93→        return () => {
 94→            if (rafRef.current) {
 95→                cancelAnimationFrame(rafRef.current);
 96→                rafRef.current = null;
 97→            }
 98→            if (engineRef.current) {
 99→                World.clear(engineRef.current.world, false);
100→                Engine.clear(engineRef.current);
101→                engineRef.current = null;
102→            }
103→            bodiesRef.current.clear();
104→            anchorsRef.current.clear();
105→            constraintsRef.current.clear();
106→            staticTimesRef.current.clear();
107→        };
108→    }, [enabled]);
109→
110→    // ── Helper: compute a star's static position (same as getComputedStarPosition) ─
111→    const computeStaticPosition = useCallback((post) => {
112→        if (!post) return null;
113→        const uid = post.users?.id ?? post.user_id;
114→        const hashGal = userHomeCoords(uid);
115→        const animGal = galaxyPositionsRef.current?.get(uid);
116→        const galDx = animGal ? (animGal.x - hashGal.x) : 0;
117→        const galDy = animGal ? (animGal.y - hashGal.y) : 0;
118→        const pull = starPullOffsets?.get(post.id);
119→
120→        const baseX = post.universe_x ?? post.display_x;
121→        const baseY = post.universe_y ?? post.display_y;
122→        if (baseX == null || baseY == null) return null;
123→
124→        return {
125→            x: baseX + galDx + (pull?.dx ?? 0),
126→            y: baseY + galDy + (pull?.dy ?? 0),
127→        };
128→    }, [starPullOffsets]);
129→
130→    // ── Body lifecycle: create/activate/deactivate based on activePostIds ──
131→    useEffect(() => {
132→        if (!enabled || !engineRef.current) return;
133→        if (!(activePostIds instanceof Set) || activePostIds.size === 0) return;
134→
135→        const engine = engineRef.current;
136→        const bodies = bodiesRef.current;
137→        const anchors = anchorsRef.current;
138→        const staticTimes = staticTimesRef.current;
139→
140→        // Activate or create bodies for active posts
141→        let created = 0;
142→        for (const postId of activePostIds) {
143→            if (created >= PHYSICS_CONFIG.maxActiveBodies) break;
144→
145→            const existing = bodies.get(postId);
146→            if (existing) {
147→                // Re-awaken if it was static
148→                if (existing.isStatic) {
149→                    Body.setStatic(existing, false);
150→                    staticTimes.delete(postId);
151→                }
152→                created++;
153→                continue;
154→            }
155→
156→            // Create new body
157→            const post = postsMapRef.current.get(postId);
158→            if (!post) continue;
159→
160→            const pos = computeStaticPosition(post);
161→            if (!pos) continue;
162→
163→            const likeCount = post.like_count != null
164→                ? post.like_count
165→                : (Array.isArray(post.likes) && post.likes[0]?.count != null
166→                    ? post.likes[0].count : 0);
167→            const radius = getStarRadius(likeCount);
168→            const mass = getStarMass(likeCount);
169→
170→            const body = createStarBody(postId, pos.x, pos.y, radius, mass);
171→            World.add(engine.world, body);
172→            bodies.set(postId, body);
