const { pairMap } = semanticMapsRef.current;
const galPositions = galaxyPositionsRef.current;

// ── Build body array (active stars + galaxy centers) ──
const bodyArray = [];
const draggedId = dragBodyRef.current?.label ?? null;

for (const [postId, body] of bodies.entries()) {
    if (body.isStatic || body.isSleeping) continue;
    bodyArray.push({
        id: postId,
        x: body.position.x,
        y: body.position.y,
        mass: body.mass,
    });
}

// Galaxy centers as virtual massive bodies
if (galPositions?.size > 0) {
    const postsByUser = new Map();
    for (const [postId] of bodies.entries()) {
        const post = postsMapRef.current.get(postId);
        if (!post) continue;
        const uid = post.users?.id ?? post.user_id;
        postsByUser.set(uid, (postsByUser.get(uid) || 0) + 1);
    }
    for (const [uid, pos] of galPositions.entries()) {
        bodyArray.push({
            id: `__galaxy_${uid}`,
            x: pos.x,
            y: pos.y,
            mass: getGalaxyMass(postsByUser.get(uid) || 0),
        });
    }
}

// ── Barnes-Hut N-body ──
const root = buildQuadTree(bodyArray);
const forces = computeBarnesHutForces(root, bodyArray, {
    G: PHYSICS_CONFIG.nBodyG,
    theta: PHYSICS_CONFIG.nBodyTheta,
    softening: PHYSICS_CONFIG.nBodySoftening,
    maxForce: PHYSICS_CONFIG.nBodyMaxForce,
    pairMap,
});

// ── Apply forces + orbit stability ──
for (const [postId, body] of bodies.entries()) {
    if (body.isStatic || body.isSleeping) continue;
    if (postId === draggedId) continue;

    // N-body gravity (galaxy pull + inter-star semantic forces)
    const force = forces.get(postId);
    if (force) {
        Body.applyForce(body, body.position, {
            x: force.fx,
            y: force.fy,
        });
    }

    // Core repulsion: push posts outward if too close to own galaxy center.
    // This prevents orbital decay/collapse caused by air friction.
    const post = postsMapRef.current.get(postId);
    if (post) {
        const uid = post.users?.id ?? post.user_id;
        const galPos = galPositions?.get(uid);
        if (galPos) {
            const dx = body.position.x - galPos.x;
            const dy = body.position.y - galPos.y;
            const dist = Math.sqrt(dx * dx + dy * dy);
            const minOrbit = PHYSICS_CONFIG.minOrbitRadius;
            if (dist < minOrbit && dist > 0.1) {
                // Strength grows as star gets closer to center
                const pushStrength = (1 - dist / minOrbit) * PHYSICS_CONFIG.coreRepulsion;
                Body.applyForce(body, body.position, {
                    x: (dx / dist) * pushStrength * body.mass,
                    y: (dy / dist) * pushStrength * body.mass,
                });
            }
        }
    }
}

