    cleanupInterval: 30000,
    staticTimeout: 30000,
    constraintBaseLength: 40,
    constraintLengthRange: 120,
    nBodyG: 2,
    nBodyTheta: 0.5,
    nBodySoftening: 30,
    nBodyMaxForce: 0.008,
    orbitSpringK: 0.0004,   // radial spring — holds posts at their natural orbit radius
    orbitalDrive: 0.0008,   // tangential push — maintains gentle rotation (~5 min per orbit at r=80)
};

export function createStarEngine() {
    const engine = Engine.create({
        gravity: { x: 0, y: 0 },
        enableSleeping: true,
    });

    engine.timing.timeScale = 1;

    return engine;
}

export function createStarBody(postId, x, y, radius, mass) {
    const body = Bodies.circle(x, y, radius, {
        label: postId,
        mass,
        frictionAir: PHYSICS_CONFIG.frictionAir,
        restitution: PHYSICS_CONFIG.restitution,
        sleepThreshold: PHYSICS_CONFIG.sleepThreshold,
    });

    return body;
}

export function createConstellationConstraint(bodyA, bodyB, similarity) {
    const length =
        PHYSICS_CONFIG.constraintBaseLength +
        (1 - similarity) * PHYSICS_CONFIG.constraintLengthRange;

    return Constraint.create({
        bodyA,
        bodyB,
        length,
        stiffness: PHYSICS_CONFIG.constraintStiffness,
        damping: PHYSICS_CONFIG.constraintDamping,
        render: { visible: false },
    });
}

export function getStarMass(likeCount) {
    const likes = Math.min(likeCount || 0, 20);
    const r = 6 + likes * 0.3;
    return Math.PI * r * r * 0.01;
}

/**
 * Virtual mass for a galaxy center in the N-body simulation.
 * Scales with how many posts the user has.
 */
export function getGalaxyMass(postCount) {
    return 10 + (postCount || 0) * 2;
}

/**
 * Compute initial orbital velocity for a star around its galaxy center.
 * Gives stars tangential velocity so they orbit rather than collapse.
 */
export function computeOrbitalVelocity(starPos, galaxyCenterPos, galaxyMass) {
    const dx = starPos.x - galaxyCenterPos.x;
    const dy = starPos.y - galaxyCenterPos.y;
    const r = Math.sqrt(dx * dx + dy * dy);
    const safeR = Math.max(r, PHYSICS_CONFIG.nBodySoftening);

    const v = Math.sqrt(PHYSICS_CONFIG.nBodyG * galaxyMass / safeR);

    // Perpendicular direction (90° rotation of radial vector)
    const invR = r > 0 ? 1 / r : 0;
    const dirX = -dy * invR; // perpendicular x
    const dirY = dx * invR;  // perpendicular y

    // Start at 25% of full orbital velocity — gravity will shape the orbit
    const scale = 0.25;
    // ±10% random perturbation to prevent perfect circles
