  1→import { useState, useEffect, useRef, useCallback, useMemo } from 'react';
  2→import {
  3→    createStarEngine,
  4→    createStarBody,
  5→    createConstellationConstraint,
  6→    getStarMass,
  7→    PHYSICS_CONFIG,
  8→    Engine,
  9→    Body,
 10→    World,
 11→    Constraint,
 12→} from '../physics/matterEngine';
 13→import { buildSemanticMaps } from '../physics/semanticForces';
 14→import { buildQuadTree, computeBarnesHutForces } from '../physics/barnesHut';
 15→import { screenToWorld } from '../utils/coordConversion';
 16→import { userHomeCoords, getStarRadius } from '../utils/starUtils';
 17→
 18→/**
 19→ * useStarPhysics — owns the Matter.js engine for star-level physics.
 20→ *
 21→ * Stars get real velocity, collision, air friction, semantic gravity,
 22→ * constellation constraints, and interactive drag-and-throw.
 23→ */
 24→export default function useStarPhysics({
 25→    posts,
 26→    activePostIds,
 27→    galaxyPositions,
 28→    starPulls,
 29→    similarPairs,
 30→    starPullOffsets,
 31→    isGalaxySettled,
 32→    camera,
 33→    zoom,
 34→    stageSize,
 35→    isStarDragging,
 36→    enabled = true,
 37→}) {
 38→    const [starBodyPositions, setStarBodyPositions] = useState(() => new Map());
 39→
 40→    // Refs for the physics engine — not in React state
 41→    const engineRef = useRef(null);
 42→    const bodiesRef = useRef(new Map());          // postId → Matter.Body
 43→    const anchorsRef = useRef(new Map());          // postId → {x, y} anchor target
 44→    const constraintsRef = useRef(new Map());      // "postA|postB" → Matter.Constraint
 45→    const staticTimesRef = useRef(new Map());      // postId → timestamp when set to static
 46→    const rafRef = useRef(null);
 47→    const frameCountRef = useRef(0);
 48→    const lastCleanupRef = useRef(Date.now());
 49→
 50→    // Drag state
 51→    const dragBodyRef = useRef(null);
 52→    const dragConstraintRef = useRef(null);
 53→    const dragPointRef = useRef(null);             // {x,y} fixed world point
 54→
 55→    // Keep latest values in refs for the RAF loop (avoids stale closures)
 56→    const galaxyPositionsRef = useRef(galaxyPositions);
 57→    const semanticMapsRef = useRef({ starPullMap: new Map(), pairMap: new Map() });
 58→    const cameraRef = useRef(camera);
 59→    const zoomRef = useRef(zoom);
 60→    const stageSizeRef = useRef(stageSize);
 61→    const postsMapRef = useRef(new Map());
 62→
 63→    // Sync refs
 64→    galaxyPositionsRef.current = galaxyPositions;
 65→    cameraRef.current = camera;
 66→    zoomRef.current = zoom;
 67→    stageSizeRef.current = stageSize;
 68→
 69→    // Build a postId → post lookup
 70→    useEffect(() => {
 71→        const map = new Map();
 72→        if (Array.isArray(posts)) {
 73→            for (const p of posts) {
 74→                if (p?.id) map.set(p.id, p);
 75→            }
 76→        }
 77→        postsMapRef.current = map;
 78→    }, [posts]);
 79→
 80→    // Pre-process semantic data into O(1) maps
 81→    useEffect(() => {
 82→        semanticMapsRef.current = buildSemanticMaps(starPulls, similarPairs);
 83→    }, [starPulls, similarPairs]);
 84→
 85→    // ── Create engine on mount ────────────────────────────────────────
 86→    useEffect(() => {
 87→        if (!enabled) return;
 88→
 89→        engineRef.current = createStarEngine();
 90→
 91→        return () => {
 92→            if (rafRef.current) {
 93→                cancelAnimationFrame(rafRef.current);
 94→                rafRef.current = null;
 95→            }
 96→            if (engineRef.current) {
 97→                World.clear(engineRef.current.world, false);
 98→                Engine.clear(engineRef.current);
 99→                engineRef.current = null;
100→            }
101→            bodiesRef.current.clear();
102→            anchorsRef.current.clear();
103→            constraintsRef.current.clear();
104→            staticTimesRef.current.clear();
105→        };
106→    }, [enabled]);
107→
108→    // ── Helper: compute a star's static position (same as getComputedStarPosition) ─
109→    const computeStaticPosition = useCallback((post) => {
110→        if (!post) return null;
111→        const uid = post.users?.id ?? post.user_id;
112→        const hashGal = userHomeCoords(uid);
113→        const animGal = galaxyPositionsRef.current?.get(uid);
114→        const galDx = animGal ? (animGal.x - hashGal.x) : 0;
115→        const galDy = animGal ? (animGal.y - hashGal.y) : 0;
116→        const pull = starPullOffsets?.get(post.id);
117→
118→        const baseX = post.universe_x ?? post.display_x;
119→        const baseY = post.universe_y ?? post.display_y;
120→        if (baseX == null || baseY == null) return null;
121→
122→        return {
123→            x: baseX + galDx + (pull?.dx ?? 0),
124→            y: baseY + galDy + (pull?.dy ?? 0),
125→        };
126→    }, [starPullOffsets]);
127→
128→    // ── Body lifecycle: create/activate/deactivate based on activePostIds ──
129→    useEffect(() => {
130→        if (!enabled || !engineRef.current) return;
131→        if (!(activePostIds instanceof Set) || activePostIds.size === 0) return;
132→
133→        const engine = engineRef.current;
134→        const bodies = bodiesRef.current;
135→        const anchors = anchorsRef.current;
136→        const staticTimes = staticTimesRef.current;
